-- Replaces per-locale objects under translations; include list-card fields (badges, duration, highlight).

UPDATE tours SET translations = COALESCE(translations, '{}'::jsonb) || $tr59877dce5425${"ko":{"title":"제주 프라이빗 차량·전문 기사｜맞춤 일일 코스","badges":["프라이빗","인기"],"duration":"9시간","highlight":"맞춤 코스","subtitle":"넓은 전용 차량과 전문 기사 겸 가이드와 함께, 대중교통 없이 제주 핵심 명소를 하루 동안 편안하게 둘러보세요.","description":"쾌적한 전용 차량과 전문 기사 겸 가이드가 동행하는 제주 맞춤 투어입니다. 이동 스트레스 없이 관심 있는 동선으로 일정을 짜고, 유네스코 자연유산과 해안 절경을 여유 있게 즐기실 수 있습니다.\n\n동·서·남부 등 원하는 권역을 바탕으로 코스를 조정할 수 있으며, 하루 종일 맞춤 안내를 받습니다.","schedule":[{"time":"09:00","title":"호텔 픽업","description":"호텔 로비에서 미팅합니다. 픽업 시간 최소 10분 전부터 로비에서 대기해 주세요."},{"time":"09:00–17:00","title":"맞춤 프라이빗 투어","description":"선택하신 동선(동부·서부·남부 등)에 따라 제주 주요 명소를 방문합니다."},{"time":"17:00","title":"호텔 드롭","description":"투어 종료 후 숙소로 모셔다 드립니다."}],"includes":["호텔 픽업·샌딩","전용 차량","전문 기사 겸 가이드(영어·중국어 가능)","유류비","통행료","주차비","세금"],"excludes":["입장권(관광지 별도)","식사·음료","팁(선택)"],"highlights":["단체 투어와 다른 여유로운 맞춤 일정","10년 이상 경력의 전문 기사 겸 가이드","호텔 픽업·샌딩으로 이동 부담 최소화","제주 유네스코 명소와 숨은 명소까지 조율 가능","넓은 냉방 차량으로 편안한 이동","영어·중국어·한국어 소통 가능(가이드 배정)","휠체어 동반 가능(사전 문의)","최대 6명까지 프라이빗 그룹"],"pickup_info":"픽업 안내\n\n제주시(제주국제공항 기준 반경 약 6km) 내 숙소는 별도 비용 없이 픽업합니다. 제주시 외 지역(서귀포·애월·한림·성산 등) 픽업 시 추가 ₩50,000이 부과될 수 있습니다.\n\n• 무료 픽업: 노형동·연동 일대 등 제주시 중심 숙소\n• 제주시 외 (+₩50,000): 서귀포·애월·한림·성산·한경·조천·표선·남원·안덕·대정·중문 등","notes":"유의사항\n\n• 초과 시간 요금: 9시간을 초과하면 시간당 ₩25,000이 현장에서 기사에게 현금 결제됩니다.\n\n• 권역 정책: 프라이빗 투어는 하루에 한 권역(예: 동부 또는 남부) 위주로 진행합니다. 당일 여러 권역을 묶어 이동할 경우 왕복 ₩60,000의 추가 요금이 발생할 수 있습니다.\n\n• 공항 픽업: 투어 당일 공항 픽업은 사전 요청 시 무료로 가능합니다.\n\n• 인원·짐: 예약 시 정확한 인원과 짐 양을 알려 주세요.\n\n• 사전 연락: 투어 전날 저녁 8시까지 스태프가 왓츠앱으로 연락드립니다. 원활한 소통을 위해 사용 중인 왓츠앱 번호를 남겨 주세요.","faqs":[{"question":"픽업 시간은 어떻게 정해지나요?","answer":"가이드가 연락드린 뒤 일정에 맞춰 조율합니다. 왓츠앱으로 직접 확인하실 수 있습니다."},{"question":"초과 시간 요금은 어떻게 되나요?","answer":"9시간 초과 시 시간당 ₩25,000을 기사에게 현금으로 지불합니다."},{"question":"하루에 여러 권역을 돌 수 있나요?","answer":"기본은 하루 한 권역입니다. 여러 권역을 묶을 경우 왕복 ₩60,000 추가 비용이 발생할 수 있습니다."},{"question":"가이드는 어떤 언어로 안내하나요?","answer":"영어·중국어·한국어 중 선택에 맞춰 전문 인력이 배정됩니다."},{"question":"무료 취소가 가능한가요?","answer":"투어 시작 24시간 전까지 취소 시 전액 환불 가능합니다."}]},"ja":{"title":"済州島プライベート車＆ドライバー付き｜好みで決める日帰りツアー","badges":["プライベート","人気"],"duration":"9時間","highlight":"自由コース","subtitle":"広々とした専用車とドライバー兼ガイドとともに、公共交通を使わず済州の名所をゆったり巡る一日。","description":"快適な専用車とプロのドライバー兼ガイドがご同行。混雑を避けながら、ご希望のエリアを中心に済州の見どころを効率よく楽しめます。\n\n東・西・南部など、興味に合わせて行程を組み、世界自然遺産や海岸の絶景を自分のペースで満喫できます。","schedule":[{"time":"09:00","title":"ホテル送迎（乗車）","description":"ホテルロビーで集合。ピックアップの少なくとも10分前からロビーでお待ちください。"},{"time":"09:00–17:00","title":"プライベート観光（コースは相談）","description":"選択したエリア（東・西・南部など）に沿って主要スポットを巡ります。"},{"time":"17:00","title":"ホテル送迎（降車）","description":"観光終了後、宿泊先へお送りします。"}],"includes":["ホテル送迎","専用車","ドライバー兼ガイド（英語・中国語可）","燃料代","通行料","駐車料金","税金"],"excludes":["観光地入場料","食事・飲料","チップ（任意）"],"highlights":["団体ツアーとは違う、ゆとりあるプライベート行程","経験豊富なドライバー兼ガイド","ホテル送迎で移動がスムーズ","ユネスコ自然遺産など、要望に合わせてコース調整","広々とした冷房付き車両","英語・中国語・日本語環境にも対応しやすいガイド","車椅子の方も事前相談で対応可能","最大6名までプライベートグループ"],"pickup_info":"送迎について\n\n済州国際空港から約6km圏内の済州市内の宿泊施設は追加料金なしでピックアップします。済州市外（西帰浦・涯月・翰林・城山など）の場合は追加 ₩50,000 が発生することがあります。\n\n• 無料エリア：ノヒョン洞・ヨンドン周辺など済州市内\n• 市外（+₩50,000）：西帰浦・涯月・翰林・城山など","notes":"ご注意\n\n• 延長料金：9時間を超える場合、1時間あたり ₩25,000 を運転手に現金でお支払いください。\n\n• エリア方針：原則として一日一エリア（東部または南部など）。複数エリアをまたぐ場合は往復 ₩60,000 の追加が発生することがあります。\n\n• 空港ピックアップ：ツアー当日の空港送迎は事前依頼で無料対応可能です。\n\n• 人数・荷物：予約時に正確な人数と荷物量をお知らせください。\n\n• 事前連絡：ツアー前日20時までにスタッフがWhatsAppでご連絡します。連絡用のWhatsApp番号をご登録ください。","faqs":[{"question":"ピックアップ時間はどう決まりますか？","answer":"ガイドからご連絡後、メッセージで調整・確定します。"},{"question":"延長料金は？","answer":"9時間超過分は1時間あたり ₩25,000 を運転手に現金でお支払いください。"},{"question":"一日で複数エリアは回れますか？","answer":"基本は一日一エリアです。複数エリアを回る場合は往復 ₩60,000 の追加がかかることがあります。"},{"question":"ガイドの言語は？","answer":"英語・中国語・韓国語のいずれかをご希望に合わせて手配します。"},{"question":"無料キャンセルはできますか？","answer":"開始24時間前までのキャンセルで全額返金可能です。"}]},"zh":{"title":"济州私人包车含司机｜行程可定制一日游","badges":["私人定制","热门"],"duration":"9小时","highlight":"行程可定制","subtitle":"宽敞专车与司导同行，不必换乘公共交通，一天内灵活串联济州热门景点。","description":"在空调专车和专业司导陪同下，按你的兴趣规划路线，轻松抵达济州世界遗产与海岸线精华。\n\n可围绕东线、西线或南部等区域定制行程，全程中文/英文沟通支持，节奏由你决定。","schedule":[{"time":"09:00","title":"酒店接载","description":"在酒店大堂集合，请至少提前10分钟抵达大堂等候。"},{"time":"09:00–17:00","title":"私人定制游览","description":"按所选区域（东/西/南部等）游览济州主要景点。"},{"time":"17:00","title":"送回酒店","description":"行程结束后送返住宿地点。"}],"includes":["酒店接送","专车使用","专业司导（可提供英语/中文服务）","油费","过路费","停车费","税费"],"excludes":["景点门票","餐饮","小费（自愿）"],"highlights":["比大团更自在的私人行程","十年以上经验的司导","酒店接送省心省力","世界遗产与小众景点可自由搭配","宽敞空调车乘坐舒适","可安排英语/中文/韩语沟通","可咨询轮椅同行","最多6人小团私密出行"],"pickup_info":"接送说明\n\n济州国际机场半径约6公里内的济州市区酒店可免费接载。若住宿位于西归浦、涯月、翰林、城山等济州以外区域，可能需另付 ₩50,000。\n\n• 免费区域：济州市 노형洞、연동 一带等\n• 市外（+₩50,000）：西归浦、涯月、翰林、城山等","notes":"重要提示\n\n• 超时费：超过9小时部分，每小时另付 ₩25,000，现场以现金支付给司机。\n\n• 区域政策：私人行程原则上一天主要游览一个区域（如东部或南部）。若当日跨多区域，可能另收往返 ₩60,000。\n\n• 机场接载：行程当天如需机场接送，可提前预约，免费。\n\n• 人数与行李：预订时请提供准确人数与行李件数。\n\n• 行前联系：工作人员会在行程前一日20:00前通过 WhatsApp 联系，请留下常用 WhatsApp 号码。","faqs":[{"question":"接载时间如何确定？","answer":"司导联系后，可通过 WhatsApp 协商确认具体时间。"},{"question":"超时如何计费？","answer":"超过9小时后，每小时 ₩25,000，以现金支付给司机。"},{"question":"一天能去多个区域吗？","answer":"建议单日聚焦一个区域。若跨区游览，可能产生往返 ₩60,000 的额外费用。"},{"question":"司导使用什么语言？","answer":"可按需求安排英语、中文或韩语服务人员。"},{"question":"可以免费取消吗？","answer":"行程开始前24小时以上取消可全额退款。"}]},"zh-TW":{"title":"濟州私人包車含司機｜客製化一日遊","badges":["私人","熱門"],"duration":"9小時","highlight":"客製行程","subtitle":"寬敞專車與司機兼導遊同行，不必轉乘大眾運輸，一天內靈活走訪濟州精選景點。","description":"在舒適冷氣專車與專業司機兼導遊陪同下，依你的興趣安排路線，輕鬆前往世界遺產與海岸美景。\n\n可選東線、西線或南部等區域，全程依你的節奏調整，並提供清楚的中文／英文溝通支援。","schedule":[{"time":"09:00","title":"飯店接駁","description":"於飯店大廳集合，請至少提前10分鐘抵達等候。"},{"time":"09:00–17:00","title":"私人客製行程","description":"依所選區域（東／西／南部等）走訪濟州主要景點。"},{"time":"17:00","title":"送回住宿","description":"行程結束後送返住宿地點。"}],"includes":["飯店接送","專車使用","專業司機兼導遊（英／中文可）","油資","過路費","停車費","稅金"],"excludes":["景點門票","餐飲","小費（自願）"],"highlights":["比大團更自在的私人行程","十年以上經驗的司機兼導遊","飯店接送省時省力","世界遺產與私房景點可彈性搭配","寬敞冷氣車乘坐舒適","可安排英語／中文／韓語服務","輪椅需求可事先洽詢","最多6人小團私密出行"],"pickup_info":"接送說明\n\n濟州國際機場方圓約6公里內的濟州市區飯店可免費接駁。若住宿位於西歸浦、涯月、翰林、城山等市外，可能需另付 ₩50,000。\n\n• 免費區域：濟州市 노형洞、연동 一帶等\n• 市外（+₩50,000）：西歸浦、涯月、翰林、城山等","notes":"注意事項\n\n• 超時費用：超過9小時後，每小時另付 ₩25,000，於現場以現金支付司機。\n\n• 區域政策：原則上一天以一個區域為主（如東部或南部）。若跨多區，可能另收往返 ₩60,000。\n\n• 機場接送：行程當日如需機場接駁，可事先預約，免費。\n\n• 人數與行李：訂位時請提供準確人數與行李量。\n\n• 行前聯絡：人員會於出發前一日20:00前以 WhatsApp 聯繫，請留下常用號碼。","faqs":[{"question":"接駁時間如何決定？","answer":"導遊聯絡後，可透過 WhatsApp 協調確認。"},{"question":"超時怎麼計費？","answer":"超過9小時後，每小時 ₩25,000，現金付給司機。"},{"question":"一天可以跑多個區域嗎？","answer":"建議單日聚焦一區。若跨區，可能另收往返 ₩60,000。"},{"question":"導遊使用哪種語言？","answer":"可依需求安排英語、中文或韓語人員。"},{"question":"可以免費取消嗎？","answer":"出發24小時前取消可全額退款。"}]},"es":{"title":"Jeju: coche privado con conductor｜Tour de día a medida","badges":["Privado","Popular"],"duration":"9 h","highlight":"Ruta a medida","subtitle":"Recorre Jeju con vehículo amplio y conductor-guía profesional, sin depender del transporte público.","description":"Disfruta de Jeju con comodidad y flexibilidad: conductor-guía en vehículo climatizado, acceso sencillo a los grandes puntos de la isla y ruta adaptable a tus intereses.\n\nOrganiza el día por zonas (este, oeste o sur) y descubre paisajes costeros y patrimonio UNESCO a tu ritmo.","schedule":[{"time":"09:00","title":"Recogida en el hotel","description":"Encuentro en el vestíbulo. Llega al menos 10 minutos antes de la hora acordada."},{"time":"09:00–17:00","title":"Tour privado a medida","description":"Visita los principales lugares según la zona elegida (este, oeste o sur de Jeju)."},{"time":"17:00","title":"Regreso al hotel","description":"Traslado de vuelta a tu alojamiento al finalizar."}],"includes":["Traslados hotel-hotel","Vehículo privado","Conductor-guía profesional (inglés/chino)","Combustible","Peajes","Aparcamiento","Impuestos"],"excludes":["Entradas a atracciones","Comidas y bebidas","Propinas (opcional)"],"highlights":["Experiencia privada más relajada que un tour grupal","Conductor-guía con amplia experiencia","Recogida y regreso en hotel","Ruta adaptable a Patrimonio UNESCO y joyas locales","Vehículo amplio con aire acondicionado","Posibilidad de guía en inglés, chino o coreano","Accesibilidad consultando con antelación","Grupo privado de hasta 6 personas"],"pickup_info":"Recogidas\n\nAlojamientos en la ciudad de Jeju (aprox. 6 km del aeropuerto) sin coste adicional. Fuera de Jeju-si (Seogwipo, Aewol, Hallim, Seongsan, etc.) puede aplicarse un suplemento de ₩50,000.\n\n• Gratis: zona de Nohyeong-dong, Yeon-dong y alrededores en Jeju-si\n• Fuera de la ciudad (+₩50,000): Seogwipo, Aewol, Hallim, Seongsan, etc.","notes":"Información importante\n\n• Horas extra: por encima de 9 h, ₩25,000/h en efectivo al conductor.\n\n• Zonas: lo habitual es una zona principal por día (este o sur, por ejemplo). Combinar varias zonas puede suponer ₩60,000 adicionales ida y vuelta.\n\n• Aeropuerto: recogida el día del tour bajo petición, sin coste.\n\n• Pasajeros y equipaje: indica número exacto al reservar.\n\n• Contacto: el equipo escribe por WhatsApp antes de las 20:00 del día previo; deja un número activo.","faqs":[{"question":"¿Cómo se fija la hora de recogida?","answer":"Tras contactarte el guía, se confirma por WhatsApp según tu horario."},{"question":"¿Cuánto cuesta el tiempo extra?","answer":"Más de 9 h: ₩25,000/h en efectivo al conductor."},{"question":"¿Puedo visitar varias zonas en un día?","answer":"Lo habitual es una zona por día. Varias zonas pueden generar un suplemento de ida y vuelta de ₩60,000."},{"question":"¿En qué idioma guía?","answer":"Se asigna guía según inglés, chino o coreano, según disponibilidad."},{"question":"¿Hay cancelación gratuita?","answer":"Sí, hasta 24 h antes del inicio con reembolso completo."}]}}$tr59877dce5425$::jsonb WHERE id = '59877dce-5425-42f4-bd59-cc4e816fdc39';

UPDATE tours SET translations = COALESCE(translations, '{}'::jsonb) || $tr0288eb78b741${"ko":{"title":"부산 핵심 명소 정통 원데이 투어｜영어 가이드","badges":["클래식 버스","영어 가이드"],"duration":"약 9시간 30분","highlight":"부산 하루 만에","subtitle":"부산에 하루뿐이라면 고민 없이 이 코스 한 번으로 핵심만 촘촘히 도는 정통 일정입니다.","description":"복잡한 옵션 없이 검증된 단일 루트로 감천문화마을, UN기념묘지, 해동용궁사, 청사포, 블루라인파크, 자갈치시장 등 부산의 대표 명소를 영어 가이드와 함께 둘러봅니다. 입장 정리와 이동이 편하고, 24시간 전까지 무료 취소가 가능합니다.","schedule":[{"time":"08:30","title":"집결","description":"해운대역 5번 출구, 부산역, 서면역 중 선택 픽업."},{"time":"09:00","title":"해동용궁사","description":"관람·약 80분."},{"time":"10:30","title":"청사포 다릿돌 전망대","description":"관람·약 30분."},{"time":"11:00","title":"로컬 식당","description":"점심(선택)·약 1시간, 비용 본인 부담."},{"time":"12:00","title":"해운대 블루라인파크 청사포역","description":"자유시간·약 40분."},{"time":"12:45","title":"광안대교","description":"차량 이동 중 경유·감상."},{"time":"13:00","title":"UN기념묘지","description":"관람·약 1시간."},{"time":"14:15","title":"감천문화마을","description":"관람·약 1시간 30분."},{"time":"16:00","title":"자갈치시장","description":"짧은 정차(약 5분)."},{"time":"17:30","title":"하차","description":"서면·부산역·해운대역 5번 출구 중 선택."}],"itinerary_details":[{"time":"08:30","activity":"3곳 중 픽업","description":"해운대역 5번 출구, 부산역, 서면역"},{"time":"09:00","activity":"해동용궁사","description":"관람(약 80분)"},{"time":"10:30","activity":"청사포 다릿돌 전망대","description":"관람(약 30분)"},{"time":"11:30","activity":"로컬 식당","description":"점심(약 1시간, 선택)"},{"time":"12:45","activity":"해운대 블루라인파크 청사포역","description":"자유시간·관람(약 40분)"},{"time":"13:45","activity":"광안대교","description":"차량 경유"},{"time":"14:00","activity":"UN기념묘지","description":"관람(약 1시간)"},{"time":"15:30","activity":"감천문화마을","description":"관람(약 1시간 30분)"},{"time":"17:15","activity":"자갈치시장","description":"짧은 정차(약 5분)"},{"time":"17:30","activity":"3곳 중 하차","description":"서면, 부산역, 해운대역 5번 출구"}],"includes":["관광지 입장료","영어 전문 가이드","통행료·주차료·유류비","광안대교 통행 비용"],"excludes":["점심 식사비(식당 안내는 포함, 비용 본인)","기타 개인 경비·개인 여행자 보험","스카이캡슐·비치트레인(현장 구매)"],"highlights":["감천문화마을","청사포·블루라인 일대","해동용궁사","자갈치시장","지정 픽업·하차"],"pickup_info":"픽업: 부산역 지하철 4번 출구(KTX 게이트 아님) 08:30, 서면역 4번 출구 08:50, 해운대역 5번 출구 09:30. 하차: 서면·부산역·해운대역 5번 출구 중 선택.","notes":"준비물: 날씨에 맞는 복장.\n\n예약 시 연락처를 정확히 남겨 주세요(왓츠앱 연락). 교통·날씨에 따라 체류 시간이나 방문지가 조정될 수 있습니다.","faqs":[{"question":"호텔 픽업이 되나요?","answer":"부산 지정 지점에서 픽업합니다. 예약 시 장소를 선택할 수 있습니다."},{"question":"인원은 어떻게 되나요?","answer":"소규모 그룹로 운영되며, 일자별 정원은 예약 화면에서 확인하실 수 있습니다."},{"question":"취소·변경은?","answer":"출발 24시간 전까지 무료 취소가 가능하며, 변경은 여유 좌석에 따라 가능합니다."},{"question":"점심은 포함인가요?","answer":"식당 안내는 드리며 식비는 본인 부담입니다."}]},"ja":{"title":"釜山定番スポット満営バスツアー｜英語ガイド同行","badges":["クラシックバス","英語ガイド"],"duration":"約9時間30分","highlight":"釜山の魅力を凝縮","subtitle":"釜山に一日しかない方へ。選び抜いた一本のコースで主要スポットを効率よく巡ります。","description":"ガムチョン、国連記念墓地、ヘドン龍宮寺、チョンサポ、ブルーライン、チャガルチ市場など、英語ガイド付きで釜山の王道を網羅。入場手配つきで移動もスムーズ。24時間前まで無料キャンセル可能です。","schedule":[{"time":"08:30","title":"集合・乗車","description":"海雲台駅5番出口、釜山駅、ソミョン駅から選択。"},{"time":"09:00","title":"ヘドン龍宮寺","description":"見学・約80分。"},{"time":"10:30","title":"チョンサポダリットル展望台","description":"見学・約30分。"},{"time":"11:00","title":"昼食（現地レストラン）","description":"任意・約1時間、食費は各自。"},{"time":"12:00","title":"ヘウンデブルーライン チョンサポ駅","description":"自由時間・約40分。"},{"time":"12:45","title":"クァンアン大橋","description":"車窓で通過。"},{"time":"13:00","title":"国連記念墓地","description":"見学・約1時間。"},{"time":"14:15","title":"ガムチョン文化村","description":"見学・約1時間30分。"},{"time":"16:00","title":"チャガルチ市場","description":"短い停車（約5分）。"},{"time":"17:30","title":"解散","description":"ソミョン・釜山駅・海雲台駅5番出口から選択。"}],"itinerary_details":[{"time":"08:30","activity":"3か所からピックアップ","description":"海雲台駅5番出口、釜山駅、ソミョン駅"},{"time":"09:00","activity":"龍宮寺","description":"見学（約80分）"},{"time":"10:30","activity":"チョンサポ展望台","description":"見学（約30分）"},{"time":"11:30","activity":"昼食","description":"約1時間・任意"},{"time":"12:45","activity":"ブルーライン チョンサポ駅","description":"自由時間（約40分）"},{"time":"13:45","activity":"クァンアン大橋","description":"車窓"},{"time":"14:00","activity":"国連記念墓地","description":"見学（約1時間）"},{"time":"15:30","activity":"ガムチョン文化村","description":"見学（約1時間30分）"},{"time":"17:15","activity":"チャガルチ市場","description":"短停車（約5分）"},{"time":"17:30","activity":"3か所で降車","description":"ソミョン、釜山駅、海雲台駅5番出口"}],"includes":["観光地入場料","英語ガイド","通行料・駐車・燃料","クァンアン大橋通行"],"excludes":["昼食代","その他個人費用・保険","スカイカプセル・ビーチトレイン（現地購入）"],"highlights":["ガムチョン文化村","チョンサポ・ブルーライン","ヘドン龍宮寺","チャガルチ市場","指定送迎"],"pickup_info":"08:30 釜山駅地下鉄4番出口（KTX口ではない）／08:50 ソミョン駅4番出口／09:30 海雲台駅5番出口。降車はソミョン・釜山駅・海雲台駅5番出口。","notes":"持ち物：天候に合わせた服装。正確な連絡先をご登録ください（WhatsApp）。交通・天候により滞在時間や順路が変わる場合があります。","faqs":[{"question":"ホテル送迎は？","answer":"釜山市内の指定ポイントからの送迎です。予約時に選択できます。"},{"question":"定員は？","answer":"日によって異なります。予約画面でご確認ください。"},{"question":"キャンセルは？","answer":"24時間前まで無料キャンセル可能です。"},{"question":"昼食は含まれますか？","answer":"レストラン案内はありますが食費は各自負担です。"}]},"zh":{"title":"釜山经典一日游｜甘川、海东龙宫寺、札嘎其","badges":["经典巴士","英语导游"],"duration":"约9.5小时","highlight":"釜山精华","subtitle":"只在釜山待一天？一条固定精华路线，省心不走冤枉路。","description":"英语导游带队，串联甘川文化村、联合国纪念公园、海东龙宫寺、청사포、蓝线公园、札嘎其市场等代表景点。含景点门票与车辆相关费用，出发前24小时可免费取消。","schedule":[{"time":"08:30","title":"集合上车","description":"海云台5号出口、釜山站、西面站三选一。"},{"time":"09:00","title":"海东龙宫寺","description":"参观约80分钟。"},{"time":"10:30","title":"青沙浦天空步道/展望","description":"参观约30分钟。"},{"time":"11:00","title":"当地餐厅","description":"午餐自理·约1小时。"},{"time":"12:00","title":"海云台蓝线公园청사포站","description":"自由活动约40分钟。"},{"time":"12:45","title":"广安大桥","description":"车行途经。"},{"time":"13:00","title":"联合国纪念陵园","description":"参观约1小时。"},{"time":"14:15","title":"甘川文化村","description":"参观约1.5小时。"},{"time":"16:00","title":"札嘎其市场","description":"短暂停靠约5分钟。"},{"time":"17:30","title":"下车","description":"西面、釜山站、海云台5号出口三选一。"}],"itinerary_details":[{"time":"08:30","activity":"三选一接载","description":"海云台5号出口、釜山站、西面站"},{"time":"09:00","activity":"龙宫寺","description":"参观（约80分钟）"},{"time":"10:30","activity":"청사포展望","description":"参观（约30分钟）"},{"time":"11:30","activity":"午餐","description":"约1小时，可选"},{"time":"12:45","activity":"蓝线청사포站","description":"自由活动（约40分钟）"},{"time":"13:45","activity":"广安大桥","description":"车览"},{"time":"14:00","activity":"联合国纪念陵园","description":"参观（约1小时）"},{"time":"15:30","activity":"甘川文化村","description":"参观（约1.5小时）"},{"time":"17:15","activity":"札嘎其市场","description":"短停（约5分钟）"},{"time":"17:30","activity":"三选一下车","description":"西面、釜山站、海云台5号出口"}],"includes":["景点门票","英语导游","过路费·停车费·油费","广安大桥通行费"],"excludes":["午餐费用","其他个人消费与保险","天空胶囊·海边列车（现场购票）"],"highlights":["甘川文化村","청사포·蓝线","海东龙宫寺","札嘎其市场","定点接送"],"pickup_info":"08:30 釜山地铁站4号出口（非KTX口）/ 08:50 西面4号出口 / 09:30 海云台5号出口。下车可选西面、釜山站、海云台5号出口。","notes":"请穿适合天气的衣物；留下准确联系方式（WhatsApp）。交通与天气可能导致停留时间或景点调整。","faqs":[{"question":"是否含酒店接送？","answer":"在釜山指定集合点上车，预订时可选择。"},{"question":"团人数多少？","answer":"为小团，具体以预订页面为准。"},{"question":"能取消或改期吗？","answer":"出发前24小时可免费取消；改期视余位而定。"},{"question":"含午餐吗？","answer":"含用餐指引，餐费自理。"}]},"zh-TW":{"title":"釜山經典一日遊｜甘川、海東龍宮寺、札嘎其","badges":["經典巴士","英語導遊"],"duration":"約9.5小時","highlight":"釜山精選","subtitle":"只在釜山待一天？固定精華路線，輕鬆走完代表景點。","description":"英語導遊帶隊，走訪甘川文化村、聯合國紀念墓園、海東龍宮寺、청사포、藍線公園、札嘎其市場等。含景點門票與車輛相關費用，出發前24小時可免費取消。","schedule":[{"time":"08:30","title":"集合上車","description":"海雲台5號出口、釜山站、西面站擇一。"},{"time":"09:00","title":"海東龍宮寺","description":"參觀約80分鐘。"},{"time":"10:30","title":"青沙浦展望","description":"參觀約30分鐘。"},{"time":"11:00","title":"當地餐廳","description":"午餐自理·約1小時。"},{"time":"12:00","title":"海雲台藍線청사포站","description":"自由活動約40分鐘。"},{"time":"12:45","title":"廣安大橋","description":"車行經過。"},{"time":"13:00","title":"聯合國紀念墓園","description":"參觀約1小時。"},{"time":"14:15","title":"甘川文化村","description":"參觀約1.5小時。"},{"time":"16:00","title":"札嘎其市場","description":"短暫停靠約5分鐘。"},{"time":"17:30","title":"下車","description":"西面、釜山站、海雲台5號出口擇一。"}],"itinerary_details":[{"time":"08:30","activity":"三選一接駁","description":"海雲台5號出口、釜山站、西面站"},{"time":"09:00","activity":"龍宮寺","description":"參觀（約80分鐘）"},{"time":"10:30","activity":"청사포展望","description":"參觀（約30分鐘）"},{"time":"11:30","activity":"午餐","description":"約1小時，可選"},{"time":"12:45","activity":"藍線청사포站","description":"自由活動（約40分鐘）"},{"time":"13:45","activity":"廣安大橋","description":"車上觀景"},{"time":"14:00","activity":"聯合國紀念墓園","description":"參觀（約1小時）"},{"time":"15:30","activity":"甘川文化村","description":"參觀（約1.5小時）"},{"time":"17:15","activity":"札嘎其市場","description":"短停（約5分鐘）"},{"time":"17:30","activity":"三選一下車","description":"西面、釜山站、海雲台5號出口"}],"includes":["景點門票","英語導遊","過路費·停車費·油資","廣安大橋通行費"],"excludes":["午餐費用","其他個人費用與保險","天空纜車·海岸列車（現場購票）"],"highlights":["甘川文化村","청사포·藍線","海東龍宮寺","札嘎其市場","定點接送"],"pickup_info":"08:30 釜山地鐵4號出口（非KTX口）／08:50 西面4號出口／09:30 海雲台5號出口。下車可選西面、釜山站、海雲台5號出口。","notes":"請依天氣著裝；留下正確聯絡方式（WhatsApp）。交通與天候可能調整停留時間或景點。","faqs":[{"question":"有飯店接送嗎？","answer":"於釜山指定地點上車，預訂時可選擇。"},{"question":"團體人數？","answer":"為小團，依預訂頁為準。"},{"question":"取消或改期？","answer":"出發24小時前免費取消；改期視余位。"},{"question":"含午餐嗎？","answer":"提供餐廳建議，餐費自理。"}]},"es":{"title":"Busán en un día｜Tour guiado auténtico","badges":["Autobús clásico","Guía en inglés"],"duration":"9,5 h","highlight":"Lo esencial","subtitle":"Si solo tienes un día, un único itinerario probado para ver lo mejor sin complicaciones.","description":"Con guía en inglés certificado: Gamcheon, Cementerio de la ONU, Haedong Yonggungsa, Cheongsapo, Blue Line Park y Jagalchi. Entradas y transporte organizados. Cancelación gratuita hasta 24 h antes.","schedule":[{"time":"08:30","title":"Recogida","description":"Haeundae salida 5, estación de Busán o Seomyeon."},{"time":"09:00","title":"Templo Haedong Yonggungsa","description":"Visita ~80 min."},{"time":"10:30","title":"Mirador Cheongsapo Daritdol","description":"Visita ~30 min."},{"time":"11:00","title":"Almuerzo","description":"Opcional ~1 h, no incluido."},{"time":"12:00","title":"Blue Line Park Cheongsapo","description":"Tiempo libre ~40 min."},{"time":"12:45","title":"Puente Gwangan","description":"Paso en vehículo."},{"time":"13:00","title":"Cementerio Memorial de la ONU","description":"Visita ~1 h."},{"time":"14:15","title":"Gamcheon","description":"Visita ~1 h 30."},{"time":"16:00","title":"Mercado Jagalchi","description":"Parada breve ~5 min."},{"time":"17:30","title":"Regreso","description":"Seomyeon, estación Busán o Haeundae salida 5."}],"itinerary_details":[{"time":"08:30","activity":"3 puntos de recogida","description":"Haeundae salida 5, Busán, Seomyeon"},{"time":"09:00","activity":"Yonggungsa","description":"Visita (80 min)"},{"time":"10:30","activity":"Mirador Cheongsapo","description":"Visita (30 min)"},{"time":"11:30","activity":"Almuerzo","description":"1 h, opcional"},{"time":"12:45","activity":"Blue Line Cheongsapo","description":"Tiempo libre (40 min)"},{"time":"13:45","activity":"Puente Gwangan","description":"Vista desde el vehículo"},{"time":"14:00","activity":"Cementerio ONU","description":"Visita (1 h)"},{"time":"15:30","activity":"Gamcheon","description":"Visita (1 h 30)"},{"time":"17:15","activity":"Jagalchi","description":"Parada (5 min)"},{"time":"17:30","activity":"3 puntos de bajada","description":"Seomyeon, Busán, Haeundae salida 5"}],"includes":["Entradas","Guía profesional en inglés","Peajes, parking, combustible","Peaje del puente Gwangan"],"excludes":["Almuerzo","Gastos personales y seguro","Sky Capsule / Beach Train (en destino)"],"highlights":["Gamcheon","Cheongsapo y Blue Line","Haedong Yonggungsa","Jagalchi","Traslados incluidos"],"pickup_info":"08:30 salida 4 estación Busán (no KTX) / 08:50 Seomyeon salida 4 / 09:30 Haeundae salida 5. Bajada en Seomyeon, Busán o Haeundae salida 5.","notes":"Ropa según clima. Deja un contacto válido (WhatsApp). Horarios y paradas pueden variar por tráfico o clima.","faqs":[{"question":"¿Recogida en hotel?","answer":"En puntos fijos de Busán; eliges al reservar."},{"question":"¿Grupo pequeño?","answer":"Sí; capacidad según fecha en la reserva."},{"question":"¿Cancelación?","answer":"Gratis hasta 24 h antes."},{"question":"¿Almuerzo incluido?","answer":"Recomendación de restaurante; pagas tú el menú."}]}}$tr0288eb78b741$::jsonb WHERE id = '0288eb78-b741-4bcf-821f-523518906753';

UPDATE tours SET translations = COALESCE(translations, '{}'::jsonb) || $trd7187d55a482${"ko":{"title":"부산 크루즈 승객 전용｜도심 관광·정시 복귀","badges":["크루즈","정시 복귀"],"duration":"9시간","highlight":"터미널 미팅","subtitle":"크루즈 입·출항 시간에 맞춰 설계된 부산 단기 관광. 터미널에서 미팅하고, 일정에 맞춰 항구로 복귀합니다.","description":"부산항에 입항하는 크루즈 여객을 위한 전용 투어입니다. 입항·출항 시각에 맞춰 픽업·샌딩을 조정하며, 용궁사·UN기념묘지·송도·감천·용두산·남포·자갈치 등 도심 명소를 가이드와 함께 둘러봅니다. 관광지 입장이 포함되며, 거리나 교통 상황에 따라 현장에서 일정이 조정될 수 있습니다.","schedule":[{"time":"가변","title":"크루즈 터미널 픽업","description":"부산국제여객터미널. 입항 시각에 맞춰 집결."},{"time":"약 1h","title":"해동용궁사","description":"해설·관람 약 1시간."},{"time":"약 1h","title":"UN기념묘지","description":"해설·관람 약 1시간."},{"time":"약 1.5h","title":"송도 해수욕장 일대","description":"해설·관람 약 1시간 30분."},{"time":"약 1h","title":"로컬 식당","description":"점심(선택), 비용 본인."},{"time":"약 1.5h","title":"감천문화마을","description":"해설·관람 약 1시간 30분."},{"time":"—","title":"용두산공원","description":"해설·관람."},{"time":"—","title":"남포동","description":"해설·관람."},{"time":"—","title":"자갈치시장","description":"해설·관람."},{"time":"가변","title":"크루즈 터미널 샌딩","description":"출항 전 터미널 복귀. 일정에 맞춰 조정."}],"includes":["부산 크루즈항 픽업·샌딩","관광지 입장료","경력 가이드","쇼핑 강요 없음","일정에 맞춘 항구 복귀"],"excludes":["식사(점심) 및 개인 경비","개인 여행자 보험","부산타워 입장(현장 선택)","송도 케이블카(현장 선택)"],"highlights":["크루즈 터미널 직접 픽업·샌딩","부산의 역사·문화·시장을 한 번에","입항 일정에 맞춘 유연한 코스","크루즈 승객 전용 일정 설계"],"pickup_info":"부산 크루즈항 픽업·샌딩. 가이드는 입항 약 1시간 전부터 터미널 안에서 \"Love Korea\" 표지판을 들고 대기합니다. 하선 후 터미널 안에서 미팅하며, 미연락 시 터미널 안에서 머물러 주세요. WhatsApp: +82 10 4521 7582.","notes":"준비물: 편한 신발, 카메라, 선크림.\n\n크루즈 입·출항 시각에 맞춰 일정이 조정됩니다(일반적으로 07:00–22:00). 06:00 조기 픽업은 인당 가이드 추가 ₩10,000이 발생할 수 있습니다. 점심은 현지 식당에서(비용 본인), 알레르기 등은 사전에 알려 주세요. 교통·날씨에 따라 방문지가 조정될 수 있습니다.","faqs":[{"question":"오후 12시에 입항해도 픽업 가능한가요?","answer":"네, 입항·출항 시각에 맞춰 일정을 조정합니다."},{"question":"오후 3시 출항 시 제시간에 복귀하나요?","answer":"출항 전 터미널로 복귀하도록 일정을 맞춥니다."},{"question":"가이드는 어디서 만나나요?","answer":"입항 약 1시간 전부터 터미널 안 \"Love Korea\" 표지판으로 대기합니다."},{"question":"점심은 포함인가요?","answer":"현지 식당에서 식사하며 비용은 본인 부담입니다."},{"question":"가이드를 못 찾으면?","answer":"터미널 안에 머물러 주시고 WhatsApp로 연락 주세요: +82 10 4521 7582."}]},"ja":{"title":"釜山クルーズ客向け｜市内観光・定時帰港","badges":["クルーズ","定時帰港"],"duration":"9時間","highlight":"ターミナル集合","subtitle":"入港・出港に合わせた釜山ショアツアー。ターミナルで合流し、安全にクルーズへ戻ります。","description":"釜山港に寄港するクルーズ客向けの市内観光です。龍宮寺、国連記念墓地、松島、甘川、龍頭山、南浦、チャガルチなどをガイド付きで巡ります。入場料込み。距離や交通状況により、現地で時間配分やスキップが調整される場合があります。","schedule":[{"time":"可変","title":"クルーズターミナル乗車","description":"釜山国際旅客ターミナル。入港に合わせて集合。"},{"time":"~1h","title":"ヘドン龍宮寺","description":"約1時間"},{"time":"~1h","title":"国連記念墓地","description":"約1時間"},{"time":"~1.5h","title":"松島エリア","description":"約1時間30分"},{"time":"~1h","title":"昼食","description":"任意、食費各自"},{"time":"~1.5h","title":"ガムチョン文化村","description":"約1時間30分"},{"time":"—","title":"ヨンドゥサン公園","description":"ガイド付き"},{"time":"—","title":"ナンポドン","description":"ガイド付き"},{"time":"—","title":"チャガルチ市場","description":"ガイド付き"},{"time":"可変","title":"クルーズターミナル降車","description":"出港前に帰港。時間は調整。"}],"includes":["釜山港送迎","観光地入場","経験ガイド","強制ショッピングなし","スケジュールに合わせた帰港"],"excludes":["食事代","個人保険","釜山タワー（任意）","松島ケーブル（任意）"],"highlights":["ターミナル直送迎","歴史・文化・市場を効率よく","寄港ダイヤに合わせた調整","クルーズ客向け設計"],"pickup_info":"ガイドは入港約1時間前からターミナル内で「Love Korea」のボードを掲げて待機します。下船後、ターミナル内で合流。WhatsApp: +82 10 4521 7582。","notes":"靴履きやすいもの、カメラ、日焼け止め。06:00早朝ピックアップは1人あたりガイド追加 ₩10,000 の場合あり。昼食は現地で各自。アレルギーは事前連絡。","faqs":[{"question":"12時入港でも大丈夫？","answer":"入港・出港に合わせて調整します。"},{"question":"15時出港に間に合う？","answer":"出港前にターミナルへ戻るよう組みます。"},{"question":"待ち合わせは？","answer":"ターミナル内「Love Korea」。"},{"question":"昼食は？","answer":"現地レストラン、食費は各自。"},{"question":"ガイドが見つからない？","answer":"ターミナル内で待機し WhatsApp へ。"}]},"zh":{"title":"釜山邮轮岸上观光｜准时送返码头","badges":["邮轮","准时回船"],"duration":"9小时","highlight":"码头集合","subtitle":"按邮轮抵离港时间设计的釜山一日游，码头上下车，灵活安排行程。","description":"专为邮轮乘客打造。含龙宫寺、联合国纪念园、松岛、甘川、龙头山、南浦、札嘎其等市区核心景点。含景点门票与持证导游。抵离时间可能因交通或距离调整停留或跳过某站，以现场为准。","schedule":[{"time":"弹性","title":"邮轮码头接载","description":"釜山国际客运码头，按船舶到达集合。"},{"time":"约1h","title":"海东龙宫寺","description":"讲解参观约1小时。"},{"time":"约1h","title":"联合国纪念陵园","description":"讲解参观约1小时。"},{"time":"约1.5h","title":"松岛一带","description":"讲解参观约1.5小时。"},{"time":"约1h","title":"当地餐厅","description":"午餐自理。"},{"time":"约1.5h","title":"甘川文化村","description":"讲解参观约1.5小时。"},{"time":"—","title":"龙头山公园","description":"讲解参观。"},{"time":"—","title":"南浦洞","description":"讲解参观。"},{"time":"—","title":"札嘎其市场","description":"讲解参观。"},{"time":"弹性","title":"送回码头","description":"开船前返回，按时刻调整。"}],"includes":["邮轮码头接送","景点门票","持证导游","无强制购物","按船期安排返港"],"excludes":["午餐及个人消费","个人旅行保险","釜山塔（现场自选）","松岛缆车（现场自选）"],"highlights":["码头直送直返","城市历史·文化·市场一线串联","随邮轮时刻灵活调整","邮轮客专属"],"pickup_info":"导游提前约1小时在航站楼内持“Love Korea”牌等候。下船后在楼内汇合，勿擅自离开。WhatsApp：+82 10 4521 7582。","notes":"请穿舒适鞋，带相机与防晒。一般接客窗口07:00–22:00；06:00早接可能每人加收导游费₩10,000。午餐在当地餐厅自理，饮食禁忌请提前告知。","faqs":[{"question":"中午才到港能接吗？","answer":"可以，按入港离港时间调整行程。"},{"question":"3点开船能赶上吗？","answer":"会按开船前安排返回码头。"},{"question":"哪里集合？","answer":"航站楼内找“Love Korea”标识。"},{"question":"含午餐吗？","answer":"当地餐厅用餐，费用自理。"},{"question":"找不到导游？","answer":"留在航站楼内并用 WhatsApp 联系。"}]},"zh-TW":{"title":"釜山郵輪岸上觀光｜準時送返碼頭","badges":["郵輪","準時回船"],"duration":"9小時","highlight":"碼頭集合","subtitle":"依郵輪抵離港時間設計的釜山觀光，碼頭上下車，行程彈性調整。","description":"專為郵輪旅客規劃。走訪龍宮寺、聯合國紀念園區、松島、甘川、龍頭山、南浦、札嘎其等。含入場與專業導遊。若路程或時間緊迫，現場可能調整或略過站點。","schedule":[{"time":"彈性","title":"郵輪碼頭接駁","description":"釜山國際客運碼頭，依船舶抵達集合。"},{"time":"約1h","title":"海東龍宮寺","description":"導覽約1小時。"},{"time":"約1h","title":"聯合國紀念墓園","description":"導覽約1小時。"},{"time":"約1.5h","title":"松島一帶","description":"導覽約1.5小時。"},{"time":"約1h","title":"當地餐廳","description":"午餐自理。"},{"time":"約1.5h","title":"甘川文化村","description":"導覽約1.5小時。"},{"time":"—","title":"龍頭山公園","description":"導覽。"},{"time":"—","title":"南浦洞","description":"導覽。"},{"time":"—","title":"札嘎其市場","description":"導覽。"},{"time":"彈性","title":"送回碼頭","description":"開船前返港，依時刻調整。"}],"includes":["郵輪碼頭接送","景點門票","專業導遊","無強制購物","依船期返港"],"excludes":["午餐與個人費用","個人旅平險","釜山塔（現場自選）","松島纜車（現場自選）"],"highlights":["碼頭直送直返","歷史・文化・市場一次走訪","配合郵輪時刻","郵輪客專屬"],"pickup_info":"導遊於入港約1小時前在航廈內持「Love Korea」牌等候。WhatsApp：+82 10 4521 7582。","notes":"請著舒適鞋、攜帶相機與防曬。午餐自理並請事先告知飲食限制。","faqs":[{"question":"中午入港可以嗎？","answer":"可以，依抵離港時間調整。"},{"question":"能準時回船嗎？","answer":"會於開船前安排返抵碼頭。"},{"question":"哪裡集合？","answer":"航廈內「Love Korea」標示。"},{"question":"含午餐嗎？","answer":"餐費自理。"},{"question":"找不到導遊？","answer":"留在航廈內並以 WhatsApp 聯絡。"}]},"es":{"title":"Busán en crucero｜Tour urbano y regreso al puerto","badges":["Crucero","Regreso a tiempo"],"duration":"9 h","highlight":"Encuentro en terminal","subtitle":"Tour urbano para pasajeros de crucero con recogida y regreso en el puerto de Busán.","description":"Pensado para escalas en Busán: templo Yonggungsa, cementerio de la ONU, Songdo, Gamcheon, Yongdusan, Nampo y Jagalchi. Entradas incluidas y guía certificado. El horario se adapta al crucero; puede acortarse o ajustarse una parada si el tiempo apremia.","schedule":[{"time":"Variable","title":"Recogida en terminal","description":"Terminal de pasajeros de Busán."},{"time":"~1h","title":"Yonggungsa","description":"~1 h"},{"time":"~1h","title":"Cementerio ONU","description":"~1 h"},{"time":"~1.5h","title":"Songdo","description":"~1 h 30"},{"time":"~1h","title":"Almuerzo","description":"Opcional, no incluido"},{"time":"~1.5h","title":"Gamcheon","description":"~1 h 30"},{"time":"—","title":"Parque Yongdusan","description":"Visita guiada"},{"time":"—","title":"Nampo-dong","description":"Visita guiada"},{"time":"—","title":"Jagalchi","description":"Visita guiada"},{"time":"Variable","title":"Regreso al crucero","description":"Antes de la salida del barco."}],"includes":["Traslado en puerto","Entradas","Guía certificado","Sin comercios forzados","Vuelta a tiempo"],"excludes":["Comidas","Seguro personal","Torre de Busán (opcional)","Teleférico Songdo (opcional)"],"highlights":["Recogida en terminal","Historia, cultura y mercados","Horario alineado al crucero","Solo pasajeros de crucero"],"pickup_info":"El guía espera dentro de la terminal con cartel «Love Korea». WhatsApp: +82 10 4521 7582.","notes":"Zapatos cómodos, cámara, protector solar. Almuerzo local no incluido; aviso de alergias con antelación.","faqs":[{"question":"¿Llegada al mediodía?","answer":"Ajustamos al horario del barco."},{"question":"¿Vuelta antes de zarpar?","answer":"Sí, planificamos el regreso al puerto."},{"question":"¿Dónde el guía?","answer":"Dentro de la terminal con el cartel indicado."},{"question":"¿Almuerzo?","answer":"En restaurante local; pagas tú."},{"question":"¿No encuentro al guía?","answer":"Permanece en la terminal y escribe por WhatsApp."}]}}$trd7187d55a482$::jsonb WHERE id = 'd7187d55-a482-4d5c-9d5a-ab6992448d82';

UPDATE tours SET translations = COALESCE(translations, '{}'::jsonb) || $trdd4a604ce328${"ko":{"title":"부산 프라이빗 투어｜국가 자격 가이드와 인기 명소","badges":["프라이빗","국가 가이드"],"duration":"4–8시간","highlight":"맞춤 코스","subtitle":"국가 자격 가이드와 전용 차량으로 부산의 해안·시장·마을을 하루 동안 유연하게 도는 맞춤 투어입니다.","description":"해동용궁사부터 블루라인 캡슐·광안대교·자갈치·국제시장·BIFF광장·국제시장·감천·송도 용궁 구름다리까지, 부산의 아이콘을 프라이빗 일정으로 연결합니다. 문화·역사·절경을 한 번에 담은 맞춤 여정입니다.","schedule":[{"time":"09:00","title":"부산 픽업","description":"호텔, 크루즈 터미널, 부산역 5번 출구 등 부산 내 지정 장소."},{"time":"09:30","title":"해동용궁사","description":"해설 관람 약 1시간. 바다 위 사찰, 108계단."},{"time":"10:30","title":"블루라인 캡슐","description":"약 40분. 사전 예약 필수(공식 사이트 안내)."},{"time":"11:30","title":"광안대교","description":"차량 경유·감상 약 10분."},{"time":"12:00","title":"포토 스톱","description":"선택, 약 20분."},{"time":"13:00","title":"자갈치시장","description":"해설 관람 약 1시간."},{"time":"14:00","title":"BIFF 광장","description":"약 30분."},{"time":"14:30","title":"국제시장","description":"약 30분."},{"time":"15:30","title":"감천문화마을","description":"해설 관람 약 1시간."},{"time":"16:30","title":"송도 용궁 구름다리","description":"약 30분."},{"time":"17:00","title":"부산 하차","description":"호텔 또는 원하는 지점."}],"includes":["호텔 픽업·샌딩","냉방 차량","국가 자격 가이드","유류·통행·주차","촬영 도움"],"excludes":["점심","입장료","팁"],"highlights":["프라이빗 가이드와 함께하는 부산 핵심 코스","해동용궁사·광안대교·감천 등 대표 스팟","자갈치·국제시장·BIFF 일대 식도락","송도 구름다리·블루라인 등 인스타 명소","일정은 그룹과 협의해 조정 가능"],"pickup_info":"숙소는 건물 1층에서 미팅. 크루즈는 부산항 세관 게이트, 부산역은 5번 출구. 부산 전역 호텔·터미널·역·게스트하우스 등 픽업 가능.","notes":"준비물: 편한 신발, 모자, 카메라, 선크림, 물. 반려동물·흡연 불가.\n\n블루라인 캡슐은 반드시 사전 온라인 예약이 필요합니다. 공식: https://www.bluelinepark.com/eng/booking.do\n픽업 09:00 기준 예: 09:30–10:00 미포→청사포, 매진 시 11:00–11:30 청사포→미포.\n출발 24시간 전까지 무료 취소. 예약만 하고 당일 결제 옵션은 정책에 따릅니다.","faqs":[{"question":"무엇이 포함되나요?","answer":"픽업·샌딩, 차량, 국가 자격 가이드, 유류·통행·주차, 촬영 도움 등이 포함됩니다."},{"question":"불포함은?","answer":"점심, 각 입장료, 팁은 불포함입니다."},{"question":"소요 시간은?","answer":"약 4–8시간이며 방문지에 따라 달라집니다."},{"question":"인원은?","answer":"최대 7명 내외 프라이빗 그룹입니다."},{"question":"휠체어 가능?","answer":"사전에 알려 주시면 가능 여부를 안내드립니다."},{"question":"언어는?","answer":"국가 자격 가이드가 영어로 진행합니다."},{"question":"캡슐 사전 예약?","answer":"네, 공식 링크로 예약해 주세요."},{"question":"취소 규정?","answer":"24시간 전까지 무료 취소 가능합니다."},{"question":"일정 변경?","answer":"프라이빗 투어로 가이드와 상의해 조정할 수 있습니다."}]},"ja":{"title":"釜山プライベートツアー｜公認ガイドと名所めぐり","badges":["プライベート","公認ガイド"],"duration":"4〜8時間","highlight":"オーダーメイド","subtitle":"公認ナショナルツアーガイドと専用車で、釜山の定番をゆったり巡るプライベートコース。","description":"龍宮寺、ブルーライン、クァンアン大橋、チャガルチ、国際市場、BIFF広場、ガムチョン、松島龍宮雲橋など、釜山の名所をつなぐオーダーメイドの一日です。","schedule":[{"time":"09:00","title":"ピックアップ","description":"ホテル・クルーズターミナル・釜山駅5番出口など。"},{"time":"09:30","title":"ヘドン龍宮寺","description":"ガイド付き約1時間。"},{"time":"10:30","title":"ブルーラインカプセル","description":"約40分。事前予約必須。"},{"time":"11:30","title":"クァンアン大橋","description":"車窓約10分。"},{"time":"12:00","title":"フォトストップ","description":"任意20分。"},{"time":"13:00","title":"チャガルチ市場","description":"約1時間。"},{"time":"14:00","title":"BIFF広場","description":"約30分。"},{"time":"14:30","title":"国際市場","description":"約30分。"},{"time":"15:30","title":"ガムチョン文化村","description":"約1時間。"},{"time":"16:30","title":"松島龍宮雲橋","description":"約30分。"},{"time":"17:00","title":"解散","description":"希望地点へ送迎。"}],"includes":["送迎","冷房車","公認ガイド","燃料・通行・駐車","撮影サポート"],"excludes":["昼食","入場料","チップ"],"highlights":["プライベート公認ガイド","龍宮寺・クァンアン・ガムチョン","市場・映画街エリア","松島雲橋","行程は相談"],"pickup_info":"ホテルは1階ロビー。クルーズは税関出口。釜山全域から送迎可能。","notes":"ブルーラインは事前予約必須: https://www.bluelinepark.com/eng/booking.do\n24時間前まで無料キャンセル。","faqs":[{"question":"含まれるものは？","answer":"送迎、車、公認ガイド、燃料・通行・駐車、撮影サポート。"},{"question":"含まれないものは？","answer":"昼食、入場料、チップ。"},{"question":"時間は？","answer":"4〜8時間程度で可変。"},{"question":"プライベート？","answer":"最大7名程度のグループ。"},{"question":"キャンセル？","answer":"24時間前まで無料。"}]},"zh":{"title":"釜山私人包车｜持证导游带你走热门景点","badges":["私人","持证导游"],"duration":"4–8小时","highlight":"行程可议","subtitle":"国家认证导游与专车，灵活串联釜山海岸、市场与彩色村落。","description":"从海东龙宫寺到蓝线胶囊列车、广安大桥、札嘎其、国际市场、BIFF广场、甘川文化村、松岛龙宫云桥，把釜山代表性体验浓缩在私人一日游中。","schedule":[{"time":"09:00","title":"釜山接载","description":"酒店、邮轮码头、釜山站5号出口等。"},{"time":"09:30","title":"海东龙宫寺","description":"讲解约1小时。"},{"time":"10:30","title":"蓝线胶囊","description":"约40分钟，须提前预约。"},{"time":"11:30","title":"广安大桥","description":"车行约10分钟。"},{"time":"12:00","title":"拍照点","description":"可选约20分钟。"},{"time":"13:00","title":"札嘎其市场","description":"约1小时。"},{"time":"14:00","title":"BIFF广场","description":"约30分钟。"},{"time":"14:30","title":"国际市场","description":"约30分钟。"},{"time":"15:30","title":"甘川文化村","description":"约1小时。"},{"time":"16:30","title":"松岛龙宫云桥","description":"约30分钟。"},{"time":"17:00","title":"釜山下车","description":"送回酒店或指定地点。"}],"includes":["酒店接送","空调车","国家认证导游","油费·过路费·停车费","协助拍照"],"excludes":["午餐","门票","小费"],"highlights":["私人包车","龙宫寺·广安·甘川","海鲜市场与国际市场","松岛云桥","行程可协商"],"pickup_info":"酒店在一楼大堂；邮轮在海关出口；釜山站5号出口。釜山范围内可协商接送点。","notes":"蓝线胶囊须提前在官网预约：https://www.bluelinepark.com/eng/booking.do\n出发前24小时可免费取消。","faqs":[{"question":"费用包含？","answer":"接送、车辆、导游、油费过路费与停车、拍照协助。"},{"question":"不含？","answer":"午餐、门票、小费。"},{"question":"时长？","answer":"约4–8小时视路线而定。"}]},"zh-TW":{"title":"釜山私人包車｜持證導遊走訪熱門景點","badges":["私人","持證導遊"],"duration":"4–8小時","highlight":"行程可調","subtitle":"國家認證導遊與專車，靈活走訪釜山海濱、市場與彩色村落。","description":"從海東龍宮寺、藍線膠囊、廣安大橋、札嘎其、國際市場、BIFF廣場、甘川到松島龍宮雲橋，把釜山代表景點串成一日私人行程。","schedule":[{"time":"09:00","title":"釜山接駁","description":"飯店、郵輪碼頭、釜山站5號出口等。"},{"time":"09:30","title":"海東龍宮寺","description":"導覽約1小時。"},{"time":"10:30","title":"藍線膠囊","description":"約40分鐘，須事先預約。"},{"time":"11:30","title":"廣安大橋","description":"車行約10分鐘。"},{"time":"12:00","title":"拍照點","description":"可選約20分鐘。"},{"time":"13:00","title":"札嘎其市場","description":"約1小時。"},{"time":"14:00","title":"BIFF廣場","description":"約30分鐘。"},{"time":"14:30","title":"國際市場","description":"約30分鐘。"},{"time":"15:30","title":"甘川文化村","description":"約1小時。"},{"time":"16:30","title":"松島龍宮雲橋","description":"約30分鐘。"},{"time":"17:00","title":"釜山下車","description":"送回住宿或指定地點。"}],"includes":["飯店接送","冷氣車","國家認證導遊","油資·過路·停車","協助拍照"],"excludes":["午餐","門票","小費"],"highlights":["私人包車","龍宮寺·廣安·甘川","市場與電影街","松島雲橋","行程可議"],"pickup_info":"飯店於大廳；郵輪於海關出口；釜山站5號出口。","notes":"藍線須事先預約：https://www.bluelinepark.com/eng/booking.do\n24小時前免費取消。","faqs":[{"question":"含什麼？","answer":"接送、車輛、導遊、油資過路與停車、拍照協助。"},{"question":"不含？","answer":"午餐、門票、小費。"}]},"es":{"title":"Busán privado｜Guía oficial y grandes vistas","badges":["Privado","Guía oficial"],"duration":"4–8 h","highlight":"Ruta flexible","subtitle":"Vehículo privado y guía nacional para ver lo esencial de Busán en un día.","description":"Desde Yonggungsa hasta Blue Line, puente Gwangan, Jagalchi, mercados, BIFF, Gamcheon y el puente de cristal; un recorrido completo y personalizado.","schedule":[{"time":"09:00","title":"Recogida","description":"Hotel, crucero o estación Busán salida 5."},{"time":"09:30","title":"Yonggungsa","description":"~1 h guiada."},{"time":"10:30","title":"Blue Line Capsule","description":"~40 min; reserva previa."},{"time":"11:30","title":"Puente Gwangan","description":"~10 min en coche."},{"time":"12:00","title":"Foto","description":"Opcional 20 min."},{"time":"13:00","title":"Jagalchi","description":"~1 h."},{"time":"14:00","title":"Plaza BIFF","description":"~30 min."},{"time":"14:30","title":"Mercado Gukje","description":"~30 min."},{"time":"15:30","title":"Gamcheon","description":"~1 h."},{"time":"16:30","title":"Puente Songdo","description":"~30 min."},{"time":"17:00","title":"Regreso","description":"Hotel o punto acordado."}],"includes":["Traslados","Vehículo climatizado","Guía nacional","Combustible, peajes y parking","Ayuda fotos"],"excludes":["Comidas","Entradas","Propinas"],"highlights":["Tour privado","Templo y puentes","Mercados","Gamcheon","Itinerario flexible"],"pickup_info":"Hoteles, terminal de cruceros y estación de Busán en todo el municipio.","notes":"Reserva obligatoria para Blue Line: https://www.bluelinepark.com/eng/booking.do\nCancelación gratis hasta 24 h antes.","faqs":[{"question":"¿Qué incluye?","answer":"Guía, vehículo, traslados, combustible y peajes."},{"question":"¿Qué no?","answer":"Comidas, entradas y propinas."}]}}$trdd4a604ce328$::jsonb WHERE id = 'dd4a604c-e328-4d24-b060-f6f4e31266ad';

UPDATE tours SET translations = COALESCE(translations, '{}'::jsonb) || $tr357e63a659fd${"ko":{"title":"제주 남부 유네스코 명소｜버스 데이 투어","badges":["클래식 버스","유네스코"],"duration":"10시간","highlight":"남부 일대","subtitle":"한라산·동백수목원·천제연·주상절리·오설록 등 제주 남부 유네스코와 절경을 하루에 담는 대표 버스 투어입니다.","description":"제주 남부의 유네스코 자연유산과 절경을 연결하는 가이드 동행 투어입니다. 어승생 탐방로에서 한라의 숲을 걷고, 동백 정원·천제연 폭포·주상절리 해안·오설록 차밭까지 이어집니다. 점심은 현지 식당에서 선택(비용 본인)이며, 쇼핑 강요 없이 관광에 집중합니다.","schedule":[{"time":"08:30","title":"픽업 - 오션스위츠 제주","description":"첫 집결 지점."},{"time":"08:45","title":"픽업 - 제주공항 3층 3번 게이트","description":"두 번째 집결."},{"time":"08:55","title":"픽업 - 롯데시티호텔 제주","description":"세 번째 집결."},{"time":"09:05","title":"픽업 - 신라면세점 제주","description":"네 번째 집결."},{"time":"09:30–11:00","title":"한라산 어승생 탐방로","description":"유네스코 자연유산 구역의 숲길과 전망."},{"time":"11:30–12:30","title":"동백힐","description":"동백 정원과 시즌별 포토 스팟. 귤 따기 체험 선택 가능."},{"time":"13:00–14:00","title":"현지 식당 점심","description":"선택, 추가 비용. 식이 제한 사전 전달."},{"time":"14:30–15:30","title":"천제연 폭포","description":"신비로운 삼단 폭포와 숲길."},{"time":"16:00–17:00","title":"주상절리","description":"용암과 파도가 빚은 기둥 절벽."},{"time":"17:30–18:00","title":"오설록 티 뮤지엄·녹차밭","description":"티 스토리와 디저트 시음."},{"time":"18:00+","title":"5곳 하차","description":"신라면세점·롯데시티·공항·오션스위츠·동문시장(자유, 하차만)."}],"includes":["입장권 일체","유네스코 버스 투어","영·중 가이드","통행·주차·유류"],"excludes":["점심 식비","개인 경비","개인 여행자 보험"],"highlights":["한라산 어승생 루트에서 숲·전망","4곳 픽업·5곳 하차(강제 쇼핑 없음)","주상절리 해안 절경","천제연 삼단 폭포","동백힐 정원과 시즌 체험"],"pickup_info":"08:30 오션스위츠 / 08:45 제주공항 국내선 3층 3번 게이트 / 08:55 롯데시티 / 09:05 신라면세점. 각 지점 10분 전 도착 권장. 10분 이상 노쇼 시 환불 불가할 수 있습니다. 짐 개수 사전 알림.","notes":"동문시장 하차는 쇼핑과 무관한 하차 지점이며 강제 쇼핑은 없습니다. 비건·할랄·채식 등 식이 제한은 가이드에게 알려 주세요.","faqs":[{"question":"점심 포함인가요?","answer":"현지 식당에서 식사하며 비용은 본인 부담입니다."},{"question":"준비물은?","answer":"편한 신발, 겉옷, 현금, 날씨에 맞는 복장."},{"question":"휠체어 가능?","answer":"본 코스는 휠체어 이용에 제한이 있을 수 있습니다."},{"question":"취소는?","answer":"24시간 전까지 무료 취소 가능합니다."},{"question":"안내 연락은?","answer":"WhatsApp 단톡으로 전날 안내드립니다. 번호를 남겨 주세요."}]},"ja":{"title":"済州島南部ユネスコ｜バス日帰りツアー","badges":["クラシックバス","ユネスコ"],"duration":"10時間","highlight":"南部エリア","subtitle":"ハルラ山・東柏ヒル・天帝淵・柱状節理・オソルロクなど南部の世界自然遺産と絶景を一日で。","description":"御乗生ルートでハルラの森を歩き、東柏の庭園、天帝淵の滝、柱状節理の海岸、オソルロク茶畑へ。昼食は現地レストラン（各自）。強制ショッピングはありません。","schedule":[{"time":"08:30","title":"ピックアップ Ocean Suites","description":"1箇所目"},{"time":"08:45","title":"済州空港3階3番ゲート","description":"2箇所目"},{"time":"08:55","title":"ロッテシティ済州","description":"3箇所目"},{"time":"09:05","title":"新羅免税店 済州","description":"4箇所目"},{"time":"09:30–11:00","title":"ハルラ山 オスンサン","description":"ユネスコ自然遺産のトレイル。"},{"time":"11:30–12:30","title":"東柏ヒル","description":"ツバキの庭、みかん狩りオプション。"},{"time":"13:00–14:00","title":"昼食","description":"任意、追加料金。"},{"time":"14:30–15:30","title":"天帝淵の滝","description":"三段の滝と森林。"},{"time":"16:00–17:00","title":"柱状節理帯","description":"熔岩の柱状岩。"},{"time":"17:30–18:00","title":"オソルロク茶ミュージアム","description":"茶畑とスイーツ。"},{"time":"18:00+","title":"5か所で降車","description":"免税店・ホテル・空港など。"}],"includes":["入場料込み","ユネスコバスツアー","英語・中国語ガイド","通行・駐車・燃料"],"excludes":["昼食","個人費用","保険"],"highlights":["ハルラ山トレイル","4ピック5ドロップ","柱状節理","天帝淵","東柏ヒル"],"pickup_info":"各10分前集合。ノーショーは返金対象外の場合あり。","notes":"東門市場降車は買い物と無関係。ヴィーガン等は事前連絡。","faqs":[{"question":"昼食は？","answer":"現地で各自、食事制限はガイドへ。"},{"question":"車椅子？","answer":"本コースは不向きです。"},{"question":"キャンセル？","answer":"24時間前まで無料。"}]},"zh":{"title":"济州南部世界遗产｜巴士一日游","badges":["经典巴士","世界遗产"],"duration":"10小时","highlight":"南部精华","subtitle":"汉拿山、山茶花之丘、天帝渊、柱状节理带、雪绿茶园，一天串联济州南部世界遗产与自然奇观。","description":"从汉拿山御乘生段到山茶花、天帝渊、柱状节理、雪绿茶博物馆，英语/中文导游同行。午餐自理，无强制购物。","schedule":[{"time":"08:30","title":"接载 海洋套房酒店","description":"第一站"},{"time":"08:45","title":"济州机场3层3号门","description":"第二站"},{"time":"08:55","title":"济州乐天城市酒店","description":"第三站"},{"time":"09:05","title":"新罗免税店济州店","description":"第四站"},{"time":"09:30–11:00","title":"汉拿山御乘生","description":"世界自然遗产徒步。"},{"time":"11:30–12:30","title":"山茶花之丘","description":"可选摘橘体验。"},{"time":"13:00–14:00","title":"午餐","description":"自理。"},{"time":"14:30–15:30","title":"天帝渊瀑布","description":"三段瀑布与森林。"},{"time":"16:00–17:00","title":"柱状节理带","description":"火山与海相遇的六角岩柱。"},{"time":"17:30–18:00","title":"雪绿茶博物馆","description":"茶园与甜品。"},{"time":"18:00+","title":"五处下车","description":"免税店、酒店、机场、东门市场等。"}],"includes":["景点门票","世界遗产巴士游","英中文导游","过路费·停车费·油费"],"excludes":["午餐","个人消费","个人保险"],"highlights":["汉拿山徒步","四接五送无购物","柱状节理","天帝渊","山茶花之丘"],"pickup_info":"请提前10分钟到达各点。行李请提前告知。","notes":"东门市场下车与购物无关；无强制购物。饮食禁忌请告知导游。","faqs":[{"question":"含午餐吗？","answer":"不含餐费，现场自理。"},{"question":"轮椅？","answer":"本线路可能不适合轮椅。"},{"question":"取消？","answer":"出发前24小时可免费取消。"}]},"zh-TW":{"title":"濟州南部世界遺產｜巴士一日遊","badges":["經典巴士","世界遺產"],"duration":"10小時","highlight":"南部精選","subtitle":"漢拏山、山茶花之丘、天帝淵、柱狀節理、雪綠茶園，一天走訪濟州南部世界自然遺產。","description":"導遊同行，串聯漢拏山、東柏、天帝淵、柱狀節理帶、雪綠茶博物館。午餐自理，無強制購物。","schedule":[{"time":"08:30","title":"接駁 Ocean Suites","description":"第一站"},{"time":"08:45","title":"濟州機場3樓3號門","description":"第二站"},{"time":"08:55","title":"樂天城市酒店","description":"第三站"},{"time":"09:05","title":"新羅免稅店","description":"第四站"},{"time":"09:30–11:00","title":"漢拏山御乘生","description":"自然遺產步道。"},{"time":"11:30–12:30","title":"山茶花之丘","description":"可選摘橘。"},{"time":"13:00–14:00","title":"午餐","description":"自理。"},{"time":"14:30–15:30","title":"天帝淵瀑布","description":""},{"time":"16:00–17:00","title":"柱狀節理帶","description":""},{"time":"17:30–18:00","title":"雪綠茶博物館","description":""},{"time":"18:00+","title":"五處下車","description":""}],"includes":["門票","巴士行程","英語／中文導遊","過路·停車·油資"],"excludes":["午餐","個人費用","個人保險"],"highlights":["漢拏山步道","四接五送","柱狀節理","天帝淵","東柏花園"],"pickup_info":"請提前10分鐘抵達；行李請提前告知。","notes":"東門市場下車僅為方便，無強制購物。","faqs":[{"question":"含午餐？","answer":"餐費自理。"},{"question":"取消？","answer":"24小時前免費取消。"}]},"es":{"title":"Jeju sur UNESCO｜Tour en autobús","badges":["Autobús clásico","UNESCO"],"duration":"10 h","highlight":"Sur de la isla","subtitle":"Hallasan, jardín de camelias, cascadas Cheonjeyeon, columnas Jusangjeolli y té O'sulloc en un día.","description":"Recorrido por el sur de Jeju con guía en inglés/chino. Almuerzo no incluido. Sin compras forzadas.","schedule":[{"time":"08:30","title":"Recogida Ocean Suites","description":""},{"time":"08:45","title":"Aeropuerto Jeju puerta 3","description":""},{"time":"08:55","title":"Lotte City Hotel","description":""},{"time":"09:05","title":"Shilla Duty Free","description":""},{"time":"09:30–11:00","title":"Hallasan Eoseungsangak","description":""},{"time":"11:30–12:30","title":"Camellia Hill","description":""},{"time":"13:00–14:00","title":"Almuerzo","description":"Opcional"},{"time":"14:30–15:30","title":"Cascadas Cheonjeyeon","description":""},{"time":"16:00–17:00","title":"Jusangjeolli","description":""},{"time":"17:30–18:00","title":"Museo del té O'sulloc","description":""},{"time":"18:00+","title":"5 bajadas","description":""}],"includes":["Entradas","Tour en autobús","Guía inglés/chino","Peajes y combustible"],"excludes":["Almuerzo","Gastos personales","Seguro"],"highlights":["Sendero Hallasan","4 recogidas / 5 paradas","Jusangjeolli","Cheonjeyeon","Camellia Hill"],"pickup_info":"Llega 10 minutos antes. Informa sobre el equipaje.","notes":"Parada en mercado Dongmun no implica compras forzadas.","faqs":[{"question":"¿Almuerzo?","answer":"No incluido."},{"question":"¿Cancelación?","answer":"Gratis hasta 24 h antes."}]}}$tr357e63a659fd$::jsonb WHERE id = '357e63a6-59fd-4e55-a5f7-11d766ed1aa5';

UPDATE tours SET translations = COALESCE(translations, '{}'::jsonb) || $trb0bd462ca1a8${"ko":{"title":"제주 크루즈 승객 전용｜일일 랜드 투어","badges":["크루즈","정시 픽업"],"duration":"8시간","highlight":"터미널 픽업·드롭","subtitle":"제주항 또는 서귀포 강정 크루즈 터미널에 맞춘 일정. 단체 차량으로 유네스코 명소를 효율적으로 둘러봅니다.","description":"크루즈 일정에 맞춰 터미널에서 픽업·샌딩합니다. 제주항 이용 시 성산일출봉 중심, 강정항 이용 시 한라산국립공원 중심으로 코스가 달라질 수 있습니다. 상품 시간은 표기상 08:00이나 실제 승선 일정에 맞춰 유연하게 조정됩니다. 단체 투어 시 입장이 포함되며, 프라이빗 차량 옵션은 별도 규정이 적용될 수 있습니다.","schedule":[{"time":"가변","title":"크루즈 터미널 픽업","description":"제주항 또는 서귀포 강정 크루즈 터미널. 선박 일정에 맞춤."},{"time":"가변","title":"코스 A: 제주항 출발","description":"성산일출봉(관람 약 2시간) - 유네스코 세계자연유산."},{"time":"가변","title":"코스 B: 강정항 출발","description":"한라산국립공원(도보·관람 약 1.5시간) - 유네스코 세계유산."}],"includes":["전문 가이드","크루즈 터미널 픽업·샌딩","단체 차량","단체 투어 시 입장료"],"excludes":["점심","개인 경비","팁","개인 여행자 보험","프라이빗 차량 옵션 시 입장"],"highlights":["크루즈 일정 맞춤 픽업·샌딩","항구별 코스 선택","제주 유네스코 명소 집중","안전한 차량·가이드"],"pickup_info":"선박 일정에 맞춰 하선 게이트 앞 \"LOVE KOREA\" 표지판으로 미팅합니다. 제주항과 강정항 중 예약 시 정확히 선택해 주세요. 일반적으로 06:00–22:00 사이 운영.","notes":"크루즈 도착·출발에 따라 시간이 변동될 수 있으며, 체류 시간이 짧으면 현장에서 일정이 축소·변경될 수 있습니다.","faqs":[{"question":"어느 항에 정박하나요?","answer":"제주항과 서귀포 강정 크루즈 터미널 두 곳이 있습니다. 예약 시 본인 선박이 정박하는 항을 선택해 주세요."},{"question":"픽업 시간은?","answer":"선박 일정에 맞춥니다. 상품에 08:00로 표기돼 있어도 입항 후 연락에 맞춰 조정됩니다."},{"question":"제시간에 복귀하나요?","answer":"출항 전 터미널로 복귀하도록 일정을 맞춥니다."}]},"ja":{"title":"済州島クルーズ客向け｜日帰り陸上観光","badges":["クルーズ","時間厳守送迎"],"duration":"8時間","highlight":"ターミナル送迎","subtitle":"済州港または西帰浦（江汀）港に合わせたコース。世界自然遺産を効率よく巡ります。","description":"寄港スケジュールに合わせてターミナルで乗降。済州港は城山日出峰、江汀港はハルラ山エリアが中心になります。表示は8:00でも実際の入港に合わせ調整。団体時は入場込み。","schedule":[{"time":"可変","title":"クルーズターミナル","description":"済州港または江汀港。"},{"time":"可変","title":"コースA 済州港","description":"城山日出峰 約2時間。"},{"time":"可変","title":"コースB 江汀港","description":"ハルラ山国立公園 約1.5時間。"}],"includes":["ガイド","ターミナル送迎","車両","団体時入場料"],"excludes":["昼食","個人費用","チップ","保険","貸切時の入場"],"highlights":["寄港ダイヤに連動","港別コース","ユネスコスポット","安全な移動"],"pickup_info":"下船ゲート前で「LOVE KOREA」の看板。港を正しく選択してください。","notes":"時間が短い場合は現地で行程を短縮する場合があります。","faqs":[{"question":"どの港？","answer":"済州港と江汀港。予約時に選択。"},{"question":"ピックアップ時間？","answer":"船のスケジュールに合わせます。"},{"question":"間に合う？","answer":"出港前にターミナルへ戻るよう調整します。"}]},"zh":{"title":"济州邮轮客专属｜全天岸上观光","badges":["邮轮","准时接送"],"duration":"8小时","highlight":"码头接送","subtitle":"济州港或西归浦江汀邮轮码头上下车，按邮轮时刻灵活安排行程。","description":"专为邮轮乘客设计。济州港侧重城山日出峰，江汀港侧重汉拿山国家公园。页面显示8:00出发，实际按船舶入港时间调整。团体团费含门票；若选私人包车，门票规则可能不同。","schedule":[{"time":"弹性","title":"邮轮码头接载","description":"济州港或西归浦江汀邮轮码头。"},{"time":"弹性","title":"A线 济州港","description":"城山日出峰，约2小时观光。"},{"time":"弹性","title":"B线 江汀港","description":"汉拿山国家公园，约1.5小时。"}],"includes":["专业导游","码头接送","舒适车辆","团体游含门票"],"excludes":["午餐","个人消费","小费","个人保险","私人包车时门票"],"highlights":["按邮轮时刻接送","双港双线路","世界遗产","安全舒适"],"pickup_info":"下船口见“LOVE KOREA”牌。预订时请选对港口。","notes":"邮轮时间变动可能导致行程压缩或调整。","faqs":[{"question":"哪个港口？","answer":"济州港与江汀港，预订时选择。"},{"question":"几点接？","answer":"按邮轮到港时间调整。"},{"question":"能准时回船吗？","answer":"会按开船前安排返港。"}]},"zh-TW":{"title":"濟州郵輪客專屬｜全日岸上觀光","badges":["郵輪","準時接送"],"duration":"8小時","highlight":"碼頭接送","subtitle":"濟州港或西歸浦江汀郵輪碼頭，依郵輪時刻調整行程。","description":"專為郵輪旅客設計。濟州港以城山日出峰為主，江汀港以漢拏山國家公園為主。頁面顯示8:00出發，實際依入港時間調整。團體含門票。","schedule":[{"time":"彈性","title":"郵輪碼頭接駁","description":"濟州港或江汀港。"},{"time":"彈性","title":"A線 濟州港","description":"城山日出峰約2小時。"},{"time":"彈性","title":"B線 江汀港","description":"漢拏山國家公園約1.5小時。"}],"includes":["導遊","碼頭接送","車輛","團體團費含門票"],"excludes":["午餐","個人費用","小費","保險","私人包車門票"],"highlights":["配合郵輪時刻","雙港路線","世界遺產","安全舒適"],"pickup_info":"下船口「LOVE KOREA」牌。預訂時選對港口。","notes":"郵輪時間變動可能壓縮行程。","faqs":[{"question":"哪個港口？","answer":"濟州港與江汀港，預訂時選擇。"},{"question":"能準時回船？","answer":"開船前返回碼頭。"}]},"es":{"title":"Jeju en día completo｜Pasajeros de crucero","badges":["Crucero","Recogida puntual"],"duration":"8 h","highlight":"Puerto recogida y regreso","subtitle":"Recogida en el puerto de Jeju o Gangjeong (Seogwipo) según tu barco.","description":"Excursión para escalas: ruta A desde puerto de Jeju (Seongsan) o B desde Gangjeong (Hallasan). La hora de la ficha es orientativa; se ajusta al crucero. Entradas incluidas en grupo.","schedule":[{"time":"Variable","title":"Terminal de crucero","description":"Jeju o Gangjeong."},{"time":"Variable","title":"Ruta A Jeju","description":"Seongsan Ilchulbong ~2 h."},{"time":"Variable","title":"Ruta B Gangjeong","description":"Parque nacional Hallasan ~1h30."}],"includes":["Guía","Traslado en puerto","Vehículo","Entradas en tour grupal"],"excludes":["Comidas","Gastos personales","Propinas","Seguro","Entradas en opción privada"],"highlights":["Horario alineado al barco","Dos puertos","UNESCO","Experiencia segura"],"pickup_info":"Cartel «LOVE KOREA» en la puerta de desembarque. Elige el puerto correcto.","notes":"El itinerario puede acortarse si el tiempo es limitado.","faqs":[{"question":"¿Qué puerto?","answer":"Jeju o Gangjeong; selección al reservar."},{"question":"¿Hora de recogida?","answer":"Según el cronograma del crucero."},{"question":"¿Vuelta a tiempo?","answer":"Sí, antes de la salida de la nave."}]}}$trb0bd462ca1a8$::jsonb WHERE id = 'b0bd462c-a1a8-4ec6-92d7-f275335f8762';

UPDATE tours SET translations = COALESCE(translations, '{}'::jsonb) || $tr592ac1da9ea2${"ko":{"title":"제주 동부 유네스코｜버스 원데이 투어","badges":["클래식 버스","유네스코"],"duration":"10시간","highlight":"동부 일주","subtitle":"함덕·해녀박물관·성산·미천굴·성읍민속마을까지 제주 동부의 유네스코와 문화를 하루에 담는 대표 코스입니다.","description":"동부·북부 일대의 유네스코 명소와 해녀 문화, 한라산 용암동굴, 전통 마을을 연결합니다. 입장료가 패키지에 포함되어 있고, 강제 쇼핑 없이 관광에만 집중합니다. 일정 순서는 교통·현장 상황에 따라 바뀔 수 있습니다.","schedule":[{"time":"08:30","title":"픽업 - 오션스위츠 제주","description":"10분 전 도착."},{"time":"08:45","title":"픽업 - 제주국제공항","description":"국내선 3층 3번 게이트. 짐 들고 바로 이동 가능."},{"time":"08:55","title":"픽업 - 롯데시티호텔 제주","description":""},{"time":"09:05","title":"픽업 - 신라면세점 제주","description":""},{"time":"09:45","title":"함덕·서우봉 해변","description":"제주 대표 해변, 봄 유채꽃 전망. 사진·자유시간."},{"time":"10:45","title":"해녀박물관","description":"유네스코 무형문화 해녀 이야기."},{"time":"12:30","title":"현지 식당 점심","description":"비용 본인. 비건·할랄 등 사전 안내."},{"time":"13:30","title":"성산일출봉","description":"세계자연유산, 대표 화산체."},{"time":"14:30","title":"미천굴 (일출랜드)","description":"만장굴 대체 방문 가능한 용암동굴."},{"time":"15:30","title":"성읍민속마을","description":"제주 전통 가옥과 생활 문화."},{"time":"18:00","title":"하차","description":"동문재래시장·오션스위츠·공항·신라면세점 등 4곳. 쇼핑 강요 없음."}],"includes":["유네스코 포함 입장료 전부","영어 가이드","밴/버스 및 기사","통행·주차·유류","강제 쇼핑 없음"],"excludes":["점심 식비","개인 경비","팁","개인 여행자 보험"],"highlights":["동부 유네스코 명소를 하루에","입장료 투명하게 포함","용암동굴 탐방","제주 시내 4곳 픽업","전문 영어 가이드"],"pickup_info":"08:30 오션스위츠 / 08:45 공항 국내선 3층 3번 / 08:55 롯데시티 / 09:05 신라면세점. 10분 전 도착. 노쇼 시 환불 불가할 수 있음. 짐 사전 알림.","notes":"교통·날씨·시설에 따라 순서가 바뀔 수 있습니다. WhatsApp 번호를 남겨 주세요. 투어 전날 단톡 안내. 동문시장·픽업 지점 하차는 쇼핑과 무관하며 강제 쇼핑 없습니다. 식이 제한은 가이드에게 알려 주세요.","faqs":[{"question":"점심 포함?","answer":"식당 안내는 하며 비용은 본인 부담입니다."},{"question":"준비물?","answer":"편한 신발, 겉옷, 현금, 날씨에 맞는 복장."},{"question":"취소?","answer":"24시간 전까지 무료 취소 가능."},{"question":"안내 연락?","answer":"전날 WhatsApp 단톡으로 일정을 공유합니다."},{"question":"특징은?","answer":"입장료 포함·쇼핑 없음·영어 가이드·쾌적 차량."}]},"ja":{"title":"済州島東部ユネスコ｜バス日帰り","badges":["クラシックバス","ユネスコ"],"duration":"10時間","highlight":"東部めぐり","subtitle":"ハムドク海岸・海女博物館・城山・ミチョングル・城邑民俗村まで、東部の世界遺産と文化を一日で。","description":"ユネスコ自然遺産と海女文化、溶岩洞窟、伝統集落をつなぐコース。入場料込み、強制ショッピングなし。順路は現地状況で変更あり。","schedule":[{"time":"08:30","title":"Ocean Suites","description":""},{"time":"08:45","title":"済州空港3階3番","description":""},{"time":"08:55","title":"ロッテシティ","description":""},{"time":"09:05","title":"新羅免税店","description":""},{"time":"09:45","title":"ハムドク・ソウボン海岸","description":""},{"time":"10:45","title":"海女博物館","description":""},{"time":"12:30","title":"昼食","description":"各自"},{"time":"13:30","title":"城山日出峰","description":""},{"time":"14:30","title":"ミチョングル洞窟","description":""},{"time":"15:30","title":"城邑民俗村","description":""},{"time":"18:00","title":"降車","description":"4か所"}],"includes":["全入場料","英語ガイド","車両","通行・駐車・燃料","ショッピングなし"],"excludes":["昼食","個人費用","チップ","保険"],"highlights":["東部ユネスコ","料金明瞭","溶岩洞窟","4ピックアップ","英語ガイド"],"pickup_info":"10分前集合。荷物は事前連絡。","notes":"WhatsAppで前日連絡。東門市場降車は買い物と無関係。","faqs":[{"question":"昼食？","answer":"各自負担。"},{"question":"キャンセル？","answer":"24時間前まで無料。"}]},"zh":{"title":"济州东部世界遗产｜巴士一日游","badges":["经典巴士","世界遗产"],"duration":"10小时","highlight":"东部环线","subtitle":"咸德、海女博物馆、城山、迷路洞穴、城邑民俗村，一天走完济州东部精华。","description":"串联东部与北部世界遗产、海女文化、熔岩洞窟与传统村落。门票全含，无强制购物。顺序可能因交通或天气调整。","schedule":[{"time":"08:30","title":"海洋套房酒店","description":"提前10分钟。"},{"time":"08:45","title":"济州机场国内线3层3号门","description":""},{"time":"08:55","title":"乐天城市酒店","description":""},{"time":"09:05","title":"新罗免税店","description":""},{"time":"09:45","title":"咸德·西峰海滩","description":"拍照与自由时间。"},{"time":"10:45","title":"海女博物馆","description":"非遗海女文化。"},{"time":"12:30","title":"午餐","description":"自理，可说明饮食限制。"},{"time":"13:30","title":"城山日出峰","description":"世界自然遗产。"},{"time":"14:30","title":"迷路洞穴（日出乐园）","description":"万丈窟关闭时的替代熔岩洞。"},{"time":"15:30","title":"城邑民俗村","description":"传统村落。"},{"time":"18:00","title":"下车","description":"东门市场等四处，无购物压力。"}],"includes":["所有景点门票","英语导游","车辆与司机","过路费·停车费·油费","无购物站"],"excludes":["午餐","个人消费","小费","个人